return items.map(item => {
  const data = item.json;

  // =========================
  // 🔥 ISQ PARSING
  // =========================
  let isqParsed = {};
  let qty = "";
  let orderValue = "";

  try {
    let raw = data.ISQ_info;

    if (typeof raw !== "string") raw = JSON.stringify(raw);
    raw = raw.replace(/\\"/g, '"');

    let parsed = JSON.parse(raw);
    if (typeof parsed === "string") parsed = JSON.parse(parsed);

    if (Array.isArray(parsed)) {
      parsed.forEach(q => {
        const key = (q?.DESC || "").trim();
        const value = (q?.RESPONSE || "").trim();
        if (!key) return;

        const k = key.toLowerCase();

        if (k.includes("quantity")) {
          qty = value;
          return;
        }

        if (k.includes("order value")) {
          orderValue = value;
          return;
        }

        isqParsed[key] = value;
      });
    }
  } catch {}

  // =========================
  // 🔥 UNIT NORMALIZATION
  // =========================
  let unit = "";

  if (qty) {
    const rawUnit = qty.replace(/[0-9]/g, "").trim().toLowerCase();

    if (rawUnit.includes("piece")) unit = "PIECE";
    else if (rawUnit.includes("bottle")) unit = "BOTTLE";
    else if (rawUnit.includes("kg") || rawUnit.includes("kilo")) unit = "KG";
    else if (rawUnit.includes("g")) unit = "G";
    else if (rawUnit.includes("ton")) unit = "TON";
    else if (rawUnit.includes("litre") || rawUnit.includes("liter")) unit = "LITRE";
    else unit = rawUnit.toUpperCase();
  }

  const mcatUnit = data.MCAT_id && unit ? `${data.MCAT_id}-${unit}` : "";

  // =========================
  // 🔥 RETAIL FLAG (ALWAYS PRESENT)
  // =========================
  let retailFlag = "No"; // ✅ default always present

  try {
    const blType =
      data.BL_Type ??
      data.bl_type ??
      data.BLTYPE ??
      null;

    if ([1, 3, 5, 6].includes(Number(blType))) {
      retailFlag = "Yes";
    }
  } catch {}

  // =========================
  // 🔥 BUYER PROFILE
  // =========================
  let buyerObj = {};

  try {
    let raw = data.Buyer_profile;

    if (typeof raw !== "string") raw = JSON.stringify(raw);
    raw = raw.replace(/\\"/g, '"');

    let parsed = JSON.parse(raw);
    if (typeof parsed === "string") parsed = JSON.parse(parsed);

    if (Array.isArray(parsed)) {
      buyerObj = parsed[0] || {};
    } else if (typeof parsed === "object" && parsed !== null) {
      const values = Object.values(parsed);
      buyerObj = values.length ? values[0] : parsed;
    }

  } catch {}

  const clean = v => (!v || v === "null" || v === "undefined") ? "" : v;

  const buyerProfile = {
    "Sells": clean(buyerObj.eto_ofr_buyer_sell_mcats) || "No Selling Activity",
    "Buys": clean(buyerObj.eto_ofr_buyer_prime_mcats)
  };

  // =========================
  // 🔥 BL CARD
  // =========================
  let blCard = [];

  try {
    let raw = data.BL_card_data;

    if (typeof raw !== "string") raw = JSON.stringify(raw);
    raw = raw.replace(/\\"/g, '"');

    let parsed = JSON.parse(raw);
    if (typeof parsed === "string") parsed = JSON.parse(parsed);

    if (!Array.isArray(parsed)) {
      if (typeof parsed === "object" && parsed !== null) {
        parsed = [parsed];
      } else {
        parsed = [];
      }
    }

    for (const b of parsed) {
      if (!b) continue;

      const itemName = (
        b.FK_PC_ITEM_NAME ||
        b.FK_PC_ITEM_DISPLAY_NAME ||
        ""
      ).toString().trim();

      if (!itemName) continue;

      const price = (b.PRODUCT_PRICE || "")
        .toString()
        .replace("\\u20b9", "₹")
        .trim();

      blCard.push({
        "Item Name": itemName,
        "Price": price
      });
    }

  } catch {
    blCard = [];
  }

  // =========================
  // 🔥 FINAL OUTPUT
  // =========================
  return {
    json: {
      Display_id: data.Display_id,
      Title: data.Title,
      MCAT: data.MCAT,
      MCAT_id: data.MCAT_id || "",

      MCAT_Unit: mcatUnit,
      Retail_Flag: retailFlag, // ✅ ALWAYS PRESENT

      ISQ: isqParsed,
      Qty: qty,
      Order_Value: orderValue,

      Buyer_profile: buyerProfile,
      BL_card: blCard
    }
  };
});

const rows = $input.all();

const map = {};

rows.forEach(item => {

  const e = item.json;

  const glcat_mcat_id = e.glcat_mcat_id || "Unknown_ID";
  const glcat_mcat_name = e.glcat_mcat_name || "Unknown";

  const rawUnit = (e.eto_ofr_qty_unit || "").trim().toLowerCase();
  const qty = Number(e.eto_ofr_qty || 0);

  //--------------------------------------------------
  // 🔥 DATA VALIDITY LAYER
  //--------------------------------------------------

  const invalidQty = qty <= 0;
  const missingUnit = !rawUnit;

  let eto_ofr_qty_unit, slab, displayUnit;

  if (missingUnit || invalidQty) {

    eto_ofr_qty_unit = "no_unit";
    displayUnit = "No_Unit";
    slab = "no_slab";
  }
  else {

    // =========================
    // 🔥 UNIT NORMALIZATION
    // =========================
    if (rawUnit.includes("piece")) {
      eto_ofr_qty_unit = "PIECE";
      displayUnit = "Piece";
    }
    else if (rawUnit.includes("bottle")) {
      eto_ofr_qty_unit = "BOTTLE";
      displayUnit = "Bottle";
    }
    else if (rawUnit.includes("kg") || rawUnit.includes("kilo")) {
      eto_ofr_qty_unit = "KG";
      displayUnit = "Kg";
    }
    else if (rawUnit.includes("g")) {
      eto_ofr_qty_unit = "G";
      displayUnit = "g";
    }
    else if (rawUnit.includes("ton")) {
      eto_ofr_qty_unit = "TON";
      displayUnit = "Ton";
    }
    else if (rawUnit.includes("litre") || rawUnit.includes("liter")) {
      eto_ofr_qty_unit = "LITRE";
      displayUnit = "Litre";
    }
    else if (rawUnit.includes("box")) {
      eto_ofr_qty_unit = "BOX";
      displayUnit = "Box";
    }
    else {
      eto_ofr_qty_unit = rawUnit.toUpperCase();

      // 🔥 Proper Case fallback
      displayUnit = rawUnit.charAt(0).toUpperCase() + rawUnit.slice(1).toLowerCase();
    }

    // =========================
    // 🔥 SLAB LOGIC
    // =========================
    if (qty <= 10) slab = "1-10";
    else if (qty <= 25) slab = "11-25";
    else if (qty <= 50) slab = "26-50";
    else if (qty <= 100) slab = "51-100";
    else if (qty <= 200) slab = "101-200";
    else slab = "200+";
  }

  //--------------------------------------------------

  const key = `${glcat_mcat_id}_${eto_ofr_qty_unit}_${slab}`;

  if (!map[key]) {
    map[key] = {
      glcat_mcat_id,
      glcat_mcat_name,
      eto_ofr_qty_unit,
      slab,

      // ✅ FINAL REQUIRED FORMAT
      MCAT_Unit: `${glcat_mcat_id}-${displayUnit}`,

      bl_apprvd: 0,
      pur: 0,
      pur_retailer: 0,
      pur_wholesaler: 0,
      retail_ni: 0,
      ni_retailer: 0,
      ni_wholesaler: 0
    };
  }

  //--------------------------------------------------

  map[key].bl_apprvd += Number(e.bl_apprvd || 0);
  map[key].pur += Number(e.pur || 0);
  map[key].pur_retailer += Number(e.pur_retailer || 0);
  map[key].pur_wholesaler += Number(e.pur_wholesaler || 0);
  map[key].retail_ni += Number(e.retail_ni || 0);
  map[key].ni_retailer += Number(e.ret_ni_cnt_retailer || 0);
  map[key].ni_wholesaler += Number(e.ret_ni_cnt_wholesaler || 0);
});


// =========================
// 🔥 SORTING LOGIC
// =========================

const slabOrder = {
  "1-10": 1,
  "11-25": 2,
  "26-50": 3,
  "51-100": 4,
  "101-200": 5,
  "200+": 6,
  "no_slab": 7
};

let result = Object.values(map);

result.sort((a, b) => {

  // 1️⃣ Sort by MCAT ID
  if (a.glcat_mcat_id !== b.glcat_mcat_id) {
    return Number(a.glcat_mcat_id) - Number(b.glcat_mcat_id);
  }

  // 2️⃣ Sort by Unit
  if (a.eto_ofr_qty_unit !== b.eto_ofr_qty_unit) {
    return a.eto_ofr_qty_unit.localeCompare(b.eto_ofr_qty_unit);
  }

  // 3️⃣ Sort by Slab
  return (slabOrder[a.slab] || 99) - (slabOrder[b.slab] || 99);
});


// =========================
// 🔥 FINAL OUTPUT
// =========================

return result.map(r => ({ json: r }));

const rows = $input.all().map(i => i.json);

// ----------------------------------
// 🔹 SPLIT DATA
// ----------------------------------

const offers = [];
const slabData = [];
const priceData = [];

rows.forEach(r => {
  if (r.Display_id) {
    offers.push(r); // File 1
  } 
  else if (r.slab && r.bl_apprvd !== undefined) {
    slabData.push(r); // Slab metrics
  } 
  else if (r.q1 !== undefined && r.median !== undefined && r.q3 !== undefined) {
    priceData.push(r); // MCAT_Price data
  }
});

// ----------------------------------
// 🔹 NORMALIZE FUNCTION
// ----------------------------------

function normalizeMCATUnit(val) {
  if (!val) return "";
  return val.toString().trim().toUpperCase();
}

// ----------------------------------
// 🔹 EXTRACT QTY
// ----------------------------------

function extractQty(qtyStr) {
  if (!qtyStr) return null;
  const match = qtyStr.toString().match(/\d+/);
  return match ? Number(match[0]) : null;
}

// ----------------------------------
// 🔹 SLAB LOGIC
// ----------------------------------

function getSlab(qty) {
  if (qty === null) return "";
  if (qty <= 10) return "1-10";
  if (qty <= 25) return "11-25";
  if (qty <= 50) return "26-50";
  if (qty <= 100) return "51-100";
  if (qty <= 200) return "101-200";
  return "200+";
}

// ----------------------------------
// 🔹 AGGREGATE SLAB DATA
// ----------------------------------

const slabMap = {};

slabData.forEach(r => {

  const normUnit = normalizeMCATUnit(r.MCAT_Unit);
  const key = `${normUnit}_${r.slab}`;

  if (!slabMap[key]) {
    slabMap[key] = {
      bl_apprvd: 0,
      pur: 0,
      pur_retailer: 0,
      pur_wholesaler: 0,
      retail_ni: 0,
      ni_retailer: 0,
      ni_wholesaler: 0
    };
  }

  slabMap[key].bl_apprvd += Number(r.bl_apprvd || 0);
  slabMap[key].pur += Number(r.pur || 0);
  slabMap[key].pur_retailer += Number(r.pur_retailer || 0);
  slabMap[key].pur_wholesaler += Number(r.pur_wholesaler || 0);
  slabMap[key].retail_ni += Number(r.retail_ni || 0);
  slabMap[key].ni_retailer += Number(r.ni_retailer || 0);
  slabMap[key].ni_wholesaler += Number(r.ni_wholesaler || 0);
});

// ----------------------------------
// 🔹 PRICE MAP (NEW)
// ----------------------------------

const priceMap = {};

priceData.forEach(r => {
  const normUnit = normalizeMCATUnit(r.MCAT_Unit);

  priceMap[normUnit] = {
    q1: Number(r.q1 || 0),
    median: Number(r.median || 0),
    q3: Number(r.q3 || 0)
  };
});

// ----------------------------------
// 🔹 MERGE
// ----------------------------------

const output = offers.map(o => {

  const qty = extractQty(o.Qty);
  const slab = getSlab(qty);
  const normUnit = normalizeMCATUnit(o.MCAT_Unit);

  // -------------------------
  // Metrics
  // -------------------------
  let metrics = {
    bl_apprvd: 0,
    pur: 0,
    pur_retailer: 0,
    pur_wholesaler: 0,
    retail_ni: 0,
    ni_retailer: 0,
    ni_wholesaler: 0
  };

  if (slab !== "") {
    const key = `${normUnit}_${slab}`;
    if (slabMap[key]) {
      metrics = slabMap[key];
    }
  }

  // -------------------------
  // Price (NEW)
  // -------------------------
  const price = priceMap[normUnit] || {
    q1: 0,
    median: 0,
    q3: 0
  };

  // -------------------------

  return {
    json: {
      ...o,

      Slab: slab,

      // Metrics
      bl_apprvd: metrics.bl_apprvd,
      pur: metrics.pur,
      pur_retailer: metrics.pur_retailer,
      pur_wholesaler: metrics.pur_wholesaler,
      retail_ni: metrics.retail_ni,
      ni_retailer: metrics.ni_retailer,
      ni_wholesaler: metrics.ni_wholesaler,

      // ✅ NEW FIELDS
      q1: price.q1,
      median: price.median,
      q3: price.q3
    }
  };
});

// ----------------------------------

return output;

return items.map(item => {
  let raw = item.json.output;

  if (!raw) return item;

  // remove ```json ``` wrappers
  raw = raw.replace(/```json/g, "").replace(/```/g, "").trim();

  let parsed = {};
  try {
    parsed = JSON.parse(raw);
  } catch (e) {}

  return {
    json: parsed
  };
});
